function riftBossConfig(l){let pool={abyss:[{name:'深渊魔王',bossType:'demon',img:'boss',r:62,hpMul:1,spdMul:1,shield:Math.floor(l/24),shoot:1.15,summon:5.2},{name:'霜月女王',bossType:'queen',img:'bossFrost',r:60,hpMul:.95,spdMul:1.1,shield:Math.floor(l/30),shoot:1.25,summon:5.5}],ruins:[{name:'遗迹巨像',bossType:'golem',img:'bossRuins',r:66,hpMul:1.2,spdMul:.82,shield:3+Math.floor(l/22),shoot:1.45,summon:6.2},{name:'深渊魔王',bossType:'demon',img:'boss',r:62,hpMul:1.05,spdMul:.96,shield:1+Math.floor(l/26),shoot:1.25,summon:5.8}],frost:[{name:'霜月女王',bossType:'queen',img:'bossFrost',r:60,hpMul:.95,spdMul:1.1,shield:Math.floor(l/30),shoot:1.25,summon:5.5},{name:'深渊魔王',bossType:'demon',img:'boss',r:62,hpMul:.98,spdMul:1.08,shield:Math.floor(l/28),shoot:1.1,summon:5.1}],bloodChapel:[{name:'血肉主祭',bossType:'demon',img:'boss',r:64,hpMul:1.12,spdMul:.96,shield:1+Math.floor(l/24),shoot:1.28,summon:5},{name:'遗迹巨像',bossType:'golem',img:'bossRuins',r:66,hpMul:1.18,spdMul:.8,shield:3+Math.floor(l/24),shoot:1.55,summon:6.3}],lavaMine:[{name:'熔炉恶魔',bossType:'demon',img:'boss',r:64,hpMul:1.08,spdMul:1.08,shield:Math.floor(l/26),shoot:1.05,summon:4.8},{name:'遗迹巨像',bossType:'golem',img:'bossRuins',r:66,hpMul:1.22,spdMul:.76,shield:3+Math.floor(l/22),shoot:1.35,summon:5.9}],poisonSwamp:[{name:'毒沼女王',bossType:'queen',img:'bossFrost',r:60,hpMul:1.02,spdMul:.98,shield:Math.floor(l/30),shoot:1.35,summon:4.9},{name:'深渊魔王',bossType:'demon',img:'boss',r:62,hpMul:1.04,spdMul:.94,shield:1+Math.floor(l/28),shoot:1.2,summon:5.4}],astralRuins:[{name:'星界审判者',bossType:'queen',img:'bossFrost',r:62,hpMul:1.08,spdMul:1.12,shield:1+Math.floor(l/28),shoot:1.18,summon:5.2},{name:'深渊魔王',bossType:'demon',img:'boss',r:62,hpMul:1,spdMul:1.14,shield:Math.floor(l/25),shoot:1.08,summon:4.9}]};let arr=pool[riftMap().id]||pool.abyss;return arr[Math.floor(Math.random()*arr.length)]}
function ensureRiftRuntime(){if(!isRift())return;S.rift.orbs=S.rift.orbs||[];S.rift.milestones=S.rift.milestones||{};S.rift.enemyPool=S.rift.enemyPool||[];S.rift.recycleQueue=S.rift.recycleQueue||[];S.rift.poolCap=riftActiveCap(S.rift.layer);S.rift.bossAddCap=riftBossAddCap(S.rift.layer)}
function riftEnemy(data){ensureRiftRuntime();let e=S.rift.enemyPool.pop()||{};for(const k in e)delete e[k];Object.assign(e,data);S.enemies.push(e);return e}
function recycleRiftEnemy(e){if(!isRift()||e.boss)return;ensureRiftRuntime();S.rift.recycleQueue.push(e)}
function flushRiftRecycle(){if(!isRift())return;ensureRiftRuntime();while(S.rift.recycleQueue.length&&S.rift.enemyPool.length<(S.rift.poolCap||220)+40)S.rift.enemyPool.push(S.rift.recycleQueue.pop());S.rift.recycleQueue.length=0}
function triggerRiftMilestone(pct){let p=S.player;if(!p)return;p.hp=Math.min(p.max,p.hp+Math.round(p.max*(pct===75?.24:.18)));if(pct>=50)p.shield=Math.min(p.max*.35,(p.shield||0)+Math.round(p.max*.08));showNotice(`秘境进度 ${pct}%：时空回响，恢复生命与护盾`)}
function riftExitBtn(){let b=document.getElementById('riftExitBtn');if(b)return b;b=document.createElement('button');b.id='riftExitBtn';b.type='button';b.textContent='退出秘境';b.style.cssText='position:absolute;left:8px;top:50%;transform:translateY(-50%);z-index:40;min-width:82px;min-height:44px;padding:10px 12px;border:1px solid rgba(250,204,21,.85);border-radius:12px;background:rgba(15,23,42,.86);color:#fde68a;font-weight:700;box-shadow:0 0 18px rgba(250,204,21,.22);display:none';b.onclick=()=>{if(isRift()&&S.rift.guardianKilled&&!S.rift.lootSaving)end(true)};document.querySelector('.game')?.appendChild(b);return b}
function updateRiftExitBtn(){let b=riftExitBtn(),saving=isRift()&&S.rift.lootSaving;b.style.display=isRift()&&S.rift.guardianKilled&&!S.over?'block':'none';b.disabled=!!saving;b.textContent=saving?'入库中':'退出秘境'}
function addRiftProgress(v){ensureRiftRuntime();let need=S.rift.progressNeed||NEED;S.kills=Math.min(need,S.kills+v);if(S.paused||S.over)return;for(const pct of [25,50,75]){let key='p'+pct,th=need*pct/100;if(S.kills>=th&&!S.rift.milestones[key]){S.rift.milestones[key]=true;triggerRiftMilestone(pct);break}}}
function grantRiftKill(e){if(!isRift()||!S.player)return;ensureRiftRuntime();S.player.xp+=e.boss?120:(e.xp||5);if(e.boss)return;if(e.elite){addRiftProgress(killProgressValue(e));S.parts.push({x:e.x,y:e.y,vx:0,vy:-14,life:.5,max:.5,a:1,c:'#c084fc',boom:52});return}S.rift.normalKills=(S.rift.normalKills||0)+1;if(S.rift.normalKills>=10){S.rift.normalKills-=10;addRiftProgress(1);S.parts.push({x:e.x,y:e.y,vx:0,vy:-10,life:.38,max:.38,a:1,c:'#a855f7',boom:34})}}
function canBreak(k){let b=BREAKS[k];if(!b)return false;let cur=S.rift.breaks?.[k]||0;if(cur>=b.max){showNotice(`${b.name} 已达到上限`);return false}return true}
function activeComboParts(){let used=new Set();for(const id of activeCombos())for(const k of S.combos[id]?.parts||[])used.add(k);return used}
function cleanComboParts(parts){let used=activeComboParts(),out=[];for(const k of parts||[])if(ATTACK_SKILLS.includes(k)&&!used.has(k)&&!out.includes(k))out.push(k);return out.slice(0,4)}
function buildCombo(parts,name){parts=cleanComboParts(parts);if(parts.length<2)return null;let sig=parts.slice().sort().join('+'),old=S.comboOrder.find(id=>S.combos[id]?.parts?.slice().sort().join('+')===sig);if(old)return old;let id='riftCombo'+(S.comboOrder.length+1);S.combos[id]={parts:parts.slice(),lv:5,name};S.comboOrder.push(id);S.fuseSigs.push(sig);normalizeCombos();return id}
function evoFor(main){let cls=S?.player?.cls||equipCls?.()||'paladin',list=Object.entries(EVOLUTIONS).filter(([,e])=>e.job===cls&&e.main===main);return list[0]}
function skillName(k){return INFO[k]?.[0]||k}
function riftSkillPool(cls){return [...new Set([...(CLASS_SKILLS[cls]||[]),...((window.RIFT_EXTRA_SKILLS||{})[cls]||[])])]}
function riftRoutes(cls){return (((window.RIFT_EXTRA_BUILDS||{})[cls]||[]).concat((BUILDS[cls]||[])))}
function customBuilds(cls){return cache.customBuilds?.[cls]||[]}
function routeOptions(){let cls=S.player.cls,routes=riftRoutes(cls),custom=customBuilds(cls).map(b=>({...b,custom:true}));if(routes.length<2)routes.push(['自由毕业流',...riftSkillPool(cls).filter(k=>ATTACK_SKILLS.includes(k)).slice(0,4),'armor','regen']);return custom.concat(routes)}
function routeName(r){return r.custom?r.name:r[0]}
function routeSkillIds(r){return r.custom?[...new Set([...Object.keys(r.skills||{}),...(r.combos||[]).flatMap(c=>c.parts||[]),...(r.evos||[]).flatMap(id=>[EVOLUTIONS[id]?.main,EVOLUTIONS[id]?.support]).filter(Boolean)])]:r.slice(1)}
function routeEvoNames(r){if(r.custom)return (r.evos||[]).map(id=>EVOLUTIONS[id]?.name).filter(Boolean).join('、')||'未指定进化';return r.slice(1).filter(k=>ATTACK_SKILLS.includes(k)).map(k=>evoFor(k)?.[1]?.name).filter(Boolean).slice(0,2).join('、')||'按核心技能补足'}
function baseRiftGrowth(){S.rift.breaks={life:0};S.rift.breakLifeFlat=0;S.player.lv=30;S.player.next=28;S.player.xp=0}
function applyCustomBuild(b){baseRiftGrowth();for(const [k,n] of Object.entries(b.skills||{}))if(S.skills[k]!==undefined)S.skills[k]=Math.min(5,Math.max(S.skills[k]||0,Math.floor(n||1)));for(const c of b.combos||[]){for(const k of c.parts||[])if(S.skills[k]!==undefined)S.skills[k]=Math.max(S.skills[k]||0,5);buildCombo((c.parts||[]).slice(0,3),c.name||`${b.name}·合成`)}for(const id of b.evos||[]){let e=EVOLUTIONS[id];if(!e)continue;if(S.skills[e.support]!==undefined)S.skills[e.support]=Math.max(S.skills[e.support]||0,3);if(S.skills[e.main]!==undefined)S.skills[e.main]=Math.max(S.skills[e.main]||0,5);S.evolutions[id]=true;S.evoCd[id]=0}S.rift.buildName=b.name;S.rift.started=true;applyArtifactStats(false,9999)}
function applyRiftBuild(idx=0){let routes=routeOptions(),route=routes[Math.max(0,Math.min(routes.length-1,idx))];if(route?.custom)return applyCustomBuild(route);let skills=route.slice(1),attacks=skills.filter(k=>ATTACK_SKILLS.includes(k)),supports=skills.filter(k=>!ATTACK_SKILLS.includes(k));for(const k of [...attacks.slice(0,4),...supports.slice(0,3),CLASSES[S.player.cls].skill])if(S.skills[k]!==undefined)S.skills[k]=ATTACK_SKILLS.includes(k)||EVO_SUPPORTS.includes(k)?5:3;let evoCount=0;for(const main of attacks){let pair=evoFor(main);if(!pair||evoCount>=2)continue;let [id,e]=pair;if(S.skills[e.support]!==undefined)S.skills[e.support]=Math.max(S.skills[e.support]||0,3);S.skills[e.main]=Math.max(S.skills[e.main]||0,5);S.evolutions[id]=true;S.evoCd[id]=0;evoCount++}if(attacks.length>=2)buildCombo(attacks.slice(0,Math.min(4,attacks.length)),route[0]+'·核心合成');S.rift.buildName=route[0];S.rift.started=true;baseRiftGrowth();applyArtifactStats(false,9999)}
function showRiftBuildSelect(){S.paused=true;let rows=routeOptions().map((r,i)=>{let name=routeName(r),skills=routeSkillIds(r).map(skillName).join(' / '),m=BUILD_META[name]||{tier:r.custom?'自创':'推荐',set:'按已穿装备补齐核心套装',unique:'按核心技能选择暗金',why:r.custom?'你保存的自定义开局，强度取决于合成链、进化和装备联动。':'按当前技能池推荐，适合先体验再调整。',train:'按短板补训练'};return `<div class="choice upgradeCard combo" data-rift-build="${i}"><h2>✦ ${esc(name)}${r.custom?'（自创）':''} <small>秘境评级 ${esc(m.tier)}</small></h2><p class="tagLine">开局技能：${esc(skills)}</p><p>进化：${esc(routeEvoNames(r))}。秘境模式开局直接成型，并改为每 5 级选择一次有限训练。</p><p class="rewardHint">推荐套装：${esc(m.set)}；推荐暗金：${esc(m.unique)}。</p><p class="rewardHint">说明：${esc(m.why)} 训练优先：${esc(m.train)}。</p><div class="choiceActions"><button type="button">选择该流派</button></div></div>`}).join('');$('levelup').querySelector('.title').textContent='选择秘境开局流派';$('choices').innerHTML=`<div class="choice upgradeCard"><h2>✦ 秘境评级系统</h2><p>${esc(RIFT_TIER_TEXT)}</p></div>${rows}`;$('levelup').classList.remove('hidden')}
function editorDraft(cls){let d=riftEditorPick[cls];if(d)return d;let pool=riftSkillPool(cls),att=pool.filter(k=>ATTACK_SKILLS.includes(k));return riftEditorPick[cls]={editId:'',name:`${Equipment?.CLS_CN?.[cls]||CLASSES[cls]?.cn||'职业'}自创流派`,skills:Object.fromEntries(pool.slice(0,6).map(k=>[k,ATTACK_SKILLS.includes(k)?5:3])),combos:[att.slice(0,4),[]],evos:Object.entries(EVOLUTIONS).filter(([,e])=>e.job===cls&&att.includes(e.main)).slice(0,2).map(([id])=>id)}}
function setDraft(cls,d){riftEditorPick[cls]={editId:d.id||'',name:d.name||'自创秘境流派',skills:{...(d.skills||{})},combos:[...((d.combos||[]).map(c=>(c.parts||[]).slice(0,4))),[],[]].slice(0,2),evos:(d.evos||[]).slice(0,2)}}
function draftBuild(cls){let d=editorDraft(cls),name=String(document.getElementById('riftBuildName')?.value||d.name||'自创秘境流派').slice(0,18),used=new Set();return{id:d.editId||('rift-custom-'+Date.now()),name,skills:capSkillPoints(d.skills,30),combos:d.combos.map((parts,i)=>{let clean=[];for(const k of parts)if(ATTACK_SKILLS.includes(k)&&!used.has(k)){used.add(k);clean.push(k)}return{name:`${name}·合成${i+1}`,parts:clean.slice(0,4),lv:5}}).filter(c=>c.parts.length>=2),evos:d.evos.slice(0,2)}}
function riftEditorHtml(){let cls=equipCls(),d=editorDraft(cls),pool=riftSkillPool(cls),att=pool.filter(k=>ATTACK_SKILLS.includes(k)),evos=Object.entries(EVOLUTIONS).filter(([,e])=>e.job===cls&&pool.includes(e.main)),saved=customBuilds(cls),used=skillPointTotal(d.skills),baseTips=riftRoutes(cls).map(r=>{let m=BUILD_META[r[0]];return m?`${r[0]}(${m.tier})：${m.set}`:r[0]}).join(' ｜ '),lockedByOther=(slot,k)=>d.combos.some((arr,i)=>i!==slot&&(arr||[]).includes(k));return `<div class="choice riftEditor"><h2>✦ 秘境开局流派自定义</h2><p class="tagLine">当前职业：${esc(Equipment.CLS_CN?.[cls]||CLASSES[cls]?.cn||cls)}。技能点 ${used}/30，保存后进入深渊秘境时优先显示自创流派。</p><p class="rewardHint">${esc(RIFT_TIER_TEXT)}</p><p class="rewardHint">最新秘境推荐：${esc(baseTips)}。</p><p class="rewardHint">可自定义：流派名、30 点开局技能等级、最多 2 条不重叠合成链、2 个已升级进化技能。</p><div class="choiceActions"><button data-rift-new-build type="button">新建流派</button>${saved.map(b=>`<span class="riftSavedBuild"><button data-rift-load-build="${esc(b.id)}" type="button">载入：${esc(b.name)}</button><button class="eqDiscard" data-rift-delete-build="${esc(b.id)}" type="button">删除</button></span>`).join('')}</div><label class="eqDetailLine"><span>流派名称</span><input id="riftBuildName" value="${esc(d.name)}" maxlength="18"></label><h3>① 开局技能等级（小按钮点击 0→5 循环）</h3><div class="riftMiniGrid">${pool.map(k=>`<button class="riftMiniBtn ${(d.skills[k]||0)?'ready':''}" data-rift-skill="${k}"><b>${esc(skillName(k))}</b><span>Lv.${d.skills[k]||0}</span></button>`).join('')}</div><h3>② 自创合成技能（每组 2-4 个攻击技能）</h3>${[0,1].map(i=>`<p class="rewardHint">合成 ${i+1}：${(d.combos[i]||[]).map(skillName).join(' + ')||'未选择'}</p><div class="riftMiniGrid">${att.map(k=>{let own=(d.combos[i]||[]).includes(k),locked=!own&&lockedByOther(i,k);return `<button class="riftMiniBtn ${own?'ready':''} ${locked?'disabled':''}" ${locked?'disabled aria-disabled="true"':''} data-rift-combo-slot="${i}" data-rift-combo-skill="${k}"><b>${esc(skillName(k))}</b><span>${own?'已选':locked?'已占用':'未选'}</span></button>`}).join('')}</div>`).join('')}<h3>③ 技能升级/进化（最多 2 个）</h3><div class="riftMiniGrid evoMini">${evos.map(([id,e])=>`<button class="riftMiniBtn ${d.evos.includes(id)?'ready':''}" data-rift-evo="${id}"><b>${esc(e.name)}</b><span>${esc(skillName(e.main))}+${esc(skillName(e.support))}</span></button>`).join('')||'<div class="evoItem">当前职业暂无可配置进化</div>'}</div><div class="choiceActions"><button data-rift-save-build type="button">保存/更新流派</button>${d.editId?`<button class="eqDiscard" data-rift-delete-build="${esc(d.editId)}" type="button">删除当前流派</button>`:''}</div></div>`}
function riftEditorStyle(){return `<style>.riftEditorModalPanel{max-height:92dvh;overflow-y:auto;overscroll-behavior:contain}.riftMiniGrid{display:grid;grid-template-columns:repeat(auto-fill,minmax(104px,1fr));gap:6px;margin:6px 0 12px}.riftMiniBtn{min-height:42px!important;padding:5px 7px!important;border-radius:9px!important;font-size:12px!important;display:flex!important;flex-direction:column;gap:2px;align-items:center;justify-content:center}.riftMiniBtn b{font-size:12px;line-height:1.1}.riftMiniBtn span{font-size:11px;opacity:.82}.riftMiniBtn.ready{outline:2px solid rgba(56,189,248,.95);background:linear-gradient(180deg,#2563eb,#4c1d95)!important;color:#e0f2fe!important;text-shadow:0 1px 2px #000;box-shadow:0 0 16px rgba(56,189,248,.48),inset 0 0 12px rgba(255,255,255,.12)!important}.riftMiniBtn.ready span{color:#bae6fd!important;opacity:1}.riftMiniBtn.disabled{filter:grayscale(1);opacity:.42;box-shadow:none!important;cursor:not-allowed}.evoMini{grid-template-columns:repeat(auto-fill,minmax(145px,1fr))}.riftSavedBuild{display:inline-flex;gap:4px;align-items:center}.riftSavedBuild button{padding:6px 8px!important;min-height:32px!important}</style>`}
function renderRiftEditor(){let sub=document.getElementById('equipSub');if(sub&&!document.getElementById('riftEditorTopBtn'))sub.insertAdjacentHTML('beforeend','<button id="riftEditorTopBtn" class="startBtn riftEditorTopBtn" data-rift-open-editor type="button">流派</button>')}
function openRiftEditor(){document.getElementById('riftEditorModal')?.remove();document.body.insertAdjacentHTML('beforeend',`<section id="riftEditorModal" class="overlay">${riftEditorStyle()}<div class="panel classPanel riftEditorModalPanel"><h1 class="title">秘境流派</h1><p class="sub">配置当前职业的秘境开局方案。</p><div id="riftEditorBody">${riftEditorHtml()}</div><p class="sub"><button data-rift-close-editor type="button">关闭</button></p></div></section>`) }
function refreshRiftEditor(){let p=document.querySelector('#riftEditorModal .riftEditorModalPanel'),b=document.getElementById('riftEditorBody');if(p&&b){let y=p.scrollTop;b.innerHTML=riftEditorHtml();requestAnimationFrame(()=>p.scrollTop=y)}else renderEquipment()}
async function saveEditorBuild(){let cls=equipCls(),b=draftBuild(cls);cache.customBuilds=normalizeBuilds(cache.customBuilds);let arr=cache.customBuilds[cls]||[],i=arr.findIndex(x=>x.id===b.id);if(i>=0)arr[i]=b;else arr.unshift(b);cache.customBuilds[cls]=arr.slice(0,8);setDraft(cls,b);await storePut(cache);openRiftEditor();showNotice('秘境自创流派已保存')}
async function deleteEditorBuild(id){let cls=equipCls();cache.customBuilds=normalizeBuilds(cache.customBuilds);cache.customBuilds[cls]=(cache.customBuilds[cls]||[]).filter(b=>b.id!==id);delete riftEditorPick[cls];await storePut(cache);openRiftEditor();showNotice('秘境自创流派已删除')}
function graduateBuild(){baseRiftGrowth();showRiftBuildSelect()}
function layerHtml(){let s=scale(selectedLayer),best=cache.best?.[selectedLayer],cost=needsKey(selectedLayer)?'消耗 1 张门票':'本层无需门票';return `<b>深渊秘境 ${selectedLayer} 层</b>：${cost}，15 分钟内填满进度并击败守卫。<br><span class="riftStats">门票 ${cache.keys} / 解锁 ${cache.maxLayer} 层 / 秘境尘 ${cache.dust}${best?` / 最佳 ${fmt(best.time)}`:''}</span><div class="riftPicker"><button data-rift-layer="-10">-10</button><button data-rift-layer="-1">-1</button><span>第 ${selectedLayer} 层</span><button data-rift-layer="1">+1</button><button data-rift-layer="10">+10</button></div><small>1-9 层免费且不掉落门票；10 层后消耗门票，打死秘境 Boss 有概率自动获得 1 张门票。</small><br><small>怪物生命 ×${s.hp.toFixed(2)}，伤害 ×${s.dmg.toFixed(2)}，精英率 ${Math.round(s.elite*100)}%。毕业装备与最强流派目标为可冲击 99 层。</small>`}
function patchUi(){if(!window.renderMaps)return;let baseRender=window.renderMaps,baseOpen=window.openMapSelect,baseLoad=window.loadMapThenStart,baseEquip=window.renderEquipment;
window.renderMaps=function(){baseRender();let btn=$('mapStart');if(selectedMap==='rift'){let tip=$('mapTip'),need=needsKey(selectedLayer);if(tip){tip.innerHTML=layerHtml();tip.classList.remove('hidden')}if(btn)btn.textContent=need?(cache.keys>0?`消耗门票进入 ${selectedLayer} 层`:'门票不足'):`免费进入 ${selectedLayer} 层`}else if(btn)btn.textContent='进入地图'};
if(baseEquip)window.renderEquipment=function(filter){baseEquip(filter);renderRiftEditor()};
window.openMapSelect=function(cls){init().finally(()=>baseOpen(cls))};
window.loadMapThenStart=async function(cls,map){if(map!=='rift')return baseLoad(cls,map);await init();let charged=false;if(needsKey(selectedLayer)&&cache.keys<=0){showNotice('秘境门票不足，1-9 层无需门票，或击败秘境 Boss 概率获得');renderMaps();return}if(selectedLayer>cache.maxLayer){showNotice(`当前只解锁到 ${cache.maxLayer} 层`);selectedLayer=cache.maxLayer;renderMaps();return}if(!await spendKey(selectedLayer)){showNotice('秘境门票不足');renderMaps();return}charged=needsKey(selectedLayer);let keys=mapAssetKeys(cls,'frost').concat(['bossRuins','bossFrost','groundChaos','groundBloodChapel','groundLavaMine','groundPoisonSwamp','groundAstralRuins','terrainAtlasRift2','frostWraith','ruinGuardian','bloodAcolyte','lavaImp','sporeSlime','voidWalker']).filter(k=>AS[k]),done=0,total=[...new Set(keys)].length;$('mapSelect').classList.add('hidden');$('loading').classList.remove('hidden');syncMusic();setLoadProgress(0,total,'深渊秘境');try{await initBootData();await Promise.all([...new Set(keys)].map(k=>loadAsset(k,AS[k],()=>setLoadProgress(++done,total,'深渊秘境'),{required:true,retries:3})));await start(cls,'rift',{riftLayer:selectedLayer})}catch(e){if(charged){cache.keys++;await storePut(cache)}console.error('秘境加载失败:',e.message,e.stack);setLoadError((e.message||'秘境加载失败')+(charged?'，已返还门票。':'。'));setTimeout(()=>{$('loading').classList.add('hidden');$('mapSelect').classList.remove('hidden');syncMusic();renderMaps()},1200)}};
document.addEventListener('click',e=>{let cls=window.equipCls?equipCls():'paladin',d=editorDraft(cls),inp=document.getElementById('riftBuildName');if(inp)d.name=inp.value;let op=e.target.closest('[data-rift-open-editor]');if(op){openRiftEditor();return}let cl=e.target.closest('[data-rift-close-editor]');if(cl){document.getElementById('riftEditorModal')?.remove();return}let ns=e.target.closest('[data-rift-new-build]');if(ns){delete riftEditorPick[cls];openRiftEditor();return}let lb=e.target.closest('[data-rift-load-build]');if(lb){let b=customBuilds(cls).find(x=>x.id===lb.dataset.riftLoadBuild);if(b){setDraft(cls,b);openRiftEditor()}return}let sk=e.target.closest('[data-rift-skill]');if(sk){let k=sk.dataset.riftSkill,n=d.skills[k]||0;if(n>=5)n=0;else{if(skillPointTotal(d.skills)>=30){showNotice('自定义技能点最多 30 点');return}n++}if(n)d.skills[k]=n;else delete d.skills[k];refreshRiftEditor();return}let cs=e.target.closest('[data-rift-combo-skill]');if(cs){let i=Number(cs.dataset.riftComboSlot||0),k=cs.dataset.riftComboSkill,arr=d.combos[i]=d.combos[i]||[],p=arr.indexOf(k);if(cs.disabled)return;if(p>=0)arr.splice(p,1);else if(arr.length<4)arr.push(k);refreshRiftEditor();return}let ev=e.target.closest('[data-rift-evo]');if(ev){let id=ev.dataset.riftEvo,p=d.evos.indexOf(id);if(p>=0)d.evos.splice(p,1);else if(d.evos.length<2)d.evos.push(id);refreshRiftEditor();return}let sv=e.target.closest('[data-rift-save-build]');if(sv){saveEditorBuild();return}let del=e.target.closest('[data-rift-delete-build]');if(del){deleteEditorBuild(del.dataset.riftDeleteBuild);return}let rb=e.target.closest('[data-rift-build]');if(rb&&isRift()){applyRiftBuild(Number(rb.dataset.riftBuild||0));$('levelup').classList.add('hidden');showNotice(`已选择秘境流派：${S.rift.buildName}`);saveGame();S.paused=false;return}let bc=e.target.closest('[data-rift-break-close]');if(bc&&isRift()){$('levelup').classList.add('hidden');S.paused=false;return}let br=e.target.closest('[data-rift-break]');if(br&&isRift()){let k=br.dataset.riftBreak;if(BREAKS[k]&&canBreak(k)){BREAKS[k].apply();$('levelup').classList.add('hidden');showNotice(`${BREAKS[k].name} +1`);saveGame();S.paused=false}return}let b=e.target.closest('[data-rift-layer]');if(!b)return;selectedLayer=Math.max(1,Math.min(cache.maxLayer,selectedLayer+Number(b.dataset.riftLayer||0)));renderMaps()});}
function patchBattle(){let baseStart=start,baseTerrain=terrainSeed,baseDelay=spawnDelay,baseCount=spawnCount,baseSpawn=spawnEnemy,baseKill=killProgressValue,baseNeed=nextBossNeed,baseWarn=updateBossWarn,baseDeaths=deaths,baseHud=updateHud,baseSave=saveData,baseLoad=loadGame,baseEnd=end,baseDrop=dropEquipmentFromBoss,baseFeedback=updateFeedback,baseAttr=enemyAttr,baseCd=skillCd,baseMod=skillMod,baseDeal=dealDamage,baseOpenLevel=openLevel,baseDrawFx=drawFx;
window.openLevel=function(){if(!isRift())return baseOpenLevel();if(!S.rift.started)return showRiftBuildSelect();if((S.player?.lv||0)%5!==0)return;S.paused=true;let keys=Object.keys(BREAKS).filter(k=>(S.rift.breaks?.[k]||0)<BREAKS[k].max).sort(()=>Math.random()-.5).slice(0,3);$('levelup').querySelector('.title').textContent='秘境训练：生存补给';$('choices').innerHTML=keys.length?keys.map(k=>{let b=BREAKS[k],lv=S.rift.breaks?.[k]||0;return `<div class="choice upgradeCard combo" data-rift-break="${k}"><h2>✦ ${b.name}</h2><p class="tagLine">当前 ${lv}/${b.max} → ${lv+1}/${b.max}</p><p>${b.desc}</p><p class="rewardHint">大秘境局内只保留生存补给；输出强度主要依赖局外装备、套装和流派成型。</p><div class="choiceActions"><button type="button">选择训练</button></div></div>`}).join(''):'<div class="choice upgradeCard combo"><h2>✦ 训练已满</h2><p>本局生存补给已达到上限，继续冲层需要提升装备与流派。</p><div class="choiceActions"><button type="button" data-rift-break-close>继续战斗</button></div></div>';$('levelup').classList.remove('hidden')};
window.terrainSeed=function(){if(S?.mapId!=='rift')return baseTerrain();let out=[],cx=WORLD_W/2,cy=WORLD_H/2,defs=riftMap().terrain;for(const [type,count,solid] of defs)for(let i=0;i<count;i++){let r=solid?rand(34,58):rand(32,90),ok=false,x=0,y=0;for(let t=0;t<60&&!ok;t++){x=rand(140,WORLD_W-140);y=rand(160,WORLD_H-160);ok=Math.hypot(x-cx,y-cy)>520&&out.every(o=>Math.hypot(x-o.x,y-o.y)>r+o.r+(solid||o.solid?88:28))}if(ok)out.push({x,y,r,type,solid:!!solid,a:rand(0,TAU),s:rand(.75,1.25)})}return out};
window.start=async function(k,mapId='chaos',opt={}){await baseStart(k,mapId);if(mapId==='rift'){let layer=Math.min(99,Math.max(1,Math.floor(opt.riftLayer||1))),map=pickRiftMap();S.rift={active:true,layer,mapTheme:map.id,mapName:map.name,timeLimit:LIMIT,progressNeed:NEED,guardianSpawned:false,guardianKilled:false,finished:false,normalKills:0,milestones:{},poolCap:riftActiveCap(layer),bossAddCap:riftBossAddCap(layer)};graduateBuild();S.nextBossKills=NEED;S.kills=0;S.bossKills=0;S.cleared=false;S.terrain=terrainSeed();showNotice(`${map.name} · 秘境 ${layer} 层开启：精英自动计进度，普通怪每 10 击杀计 1 点`);updateHud();saveGame()}};
window.skillCd=function(id,base,min){return baseCd(id,base,min)};
window.skillMod=function(id,key){return baseMod(id,key)};
window.dealDamage=function(e,d,steal=false,id=''){return baseDeal(e,d,steal,id)};
window.spawnDelay=function(){if(!isRift())return baseDelay();return .32};
window.spawnCount=function(){if(!isRift())return baseCount();if(S.rift.guardianSpawned)return 0;ensureRiftRuntime();let need=Math.max(0,(S.rift.poolCap||riftActiveCap(S.rift.layer))-riftAddCount());return Math.min(riftSpawnBatch(S.rift.layer),need)};
window.killProgressValue=function(e){if(!isRift())return baseKill(e);if(e.boss)return 0;if(e.type==='shield'||e.type==='guardian')return 5;if(['bloodAcolyte','lavaImp','sporeSlime','voidWalker'].includes(e.type))return e.elite?7:3;if(e.elite)return 7;if(e.type==='wraith'||e.type==='healer'||e.type==='charger')return 4;if(e.type==='slime')return e.mini?1:2;return 1};
window.nextBossNeed=function(){return isRift()?NEED:baseNeed()};
window.spawnEnemy=function(boss=false,forced=null){if(!isRift())return baseSpawn(boss,forced);ensureRiftRuntime();let addCap=S.rift.guardianSpawned?(S.rift.bossAddCap||riftBossAddCap(S.rift.layer)):(S.rift.poolCap||riftActiveCap(S.rift.layer));if(!boss&&riftAddCount()>=addCap)return false;let pos=safeSpawn(edgePos(),boss?130:48),d=(1+S.time/110)*mapRule().diff,rs=scale(S.rift.layer),l=S.rift.layer;if(boss){if(S.rift.guardianSpawned)return false;clearRiftAdds();S.rift.guardianSpawned=true;S.rift.bossAddCap=riftBossAddCap(l);let bc=riftBossConfig(l),hp=2300*d*rs.bossHp*bc.hpMul,spd=(42+l*.65)*bc.spdMul;showNotice(`${bc.name}降临！已清空小怪，击败它完成秘境 ${l} 层`);S.shake=.45;S.enemies.push({...pos,type:'boss',bossType:bc.bossType,img:bc.img,r:bc.r,hp,max:hp,spd,baseSpd:spd,boss:true,elite:true,hit:0,slow:0,phase:rand(0,TAU),shoot:bc.shoot,summon:bc.summon,stage:0,anim:rand(0,4),shield:bc.shield,dmgMul:rs.bossDmg});return true}let elite=Math.random()<rs.elite,type=forced||riftType(l,elite),cfg={imp:{img:'imp',r:16,hp:20*d,spd:52+d*8,xp:4},skeleton:{img:'skeleton',r:20,hp:44*d*(l>=71?1.45:1),spd:42+d*5,xp:7},slime:{img:'slime',r:27,hp:78*d*(l>=71?1.25:1),spd:25+d*3,xp:10,split:2},eye:{img:'eye',r:21,hp:42*d,spd:32+d*2,xp:8,range:260,shoot:rand(l>=71?4.8:5.8,l>=71?7:8.2)},wraith:{img:'frostWraith',r:23,hp:82*d,spd:45+d*4,xp:17,elite:true,range:250,frost:6.2},guardian:{img:'ruinGuardian',r:25,hp:120*d,spd:32+d*3,xp:20,elite:true,shield:2+Math.floor(l/35),stomp:6.6},shield:{img:'skeleton',r:24,hp:98*d,spd:36+d*4,xp:16,elite:true,shield:1+Math.floor(l/30)},charger:{img:'imp',r:22,hp:76*d,spd:45+d*5,xp:15,elite:true,charge:rand(1.1,2.2),dash:0},healer:{img:'eye',r:23,hp:70*d,spd:30+d*3,xp:18,elite:true,heal:2.1},bloodAcolyte:{img:'bloodAcolyte',r:22,hp:86*d,spd:38+d*4,xp:15,elite:elite||l>=35,range:230,shoot:rand(4.5,6.8)},lavaImp:{img:'lavaImp',r:20,hp:68*d,spd:58+d*6,xp:13,elite:elite||l>=40,charge:rand(1,2),dash:0},sporeSlime:{img:'sporeSlime',r:26,hp:96*d,spd:26+d*3,xp:14,elite:elite||l>=35,split:2,heal:2.8},voidWalker:{img:'voidWalker',r:23,hp:84*d,spd:47+d*5,xp:16,elite:elite||l>=30,range:280,shoot:rand(3.8,6)}}[type];cfg.hp*=rs.hp;cfg.spd*=1+Math.min(.55,l*.006);return riftEnemy({...pos,type,boss:false,hit:0,slow:0,phase:rand(0,TAU),shoot:rand(2.2,4.2),anim:rand(0,4),dmgMul:rs.dmg,...cfg,max:cfg.hp})};
window.updateBossWarn=function(){if(!isRift())return baseWarn();let left=NEED-S.kills,el=$('bossWarn');if(!S.rift.guardianSpawned&&left>0&&left<=12&&!S.paused&&!S.over){el.textContent=`秘境守卫即将降临，还需进度 ${left}`;el.classList.remove('hidden')}else el.classList.add('hidden')};
window.updateHud=function(){baseHud();if(!isRift()||!S.player)return;let label=document.querySelector('#hudBoss label span:first-child');if(label)label.textContent='守护者封印';let b=S.rift.breaks||{},sum=Object.values(b).reduce((a,c)=>a+c,0);$('job').textContent=`${S.player.job} · ${riftMapName()}${S.rift.layer}层 · 突破${sum}`;$('tm').textContent=fmt(Math.max(0,S.rift.timeLimit-S.time));let progress=Math.min(S.kills,S.rift.progressNeed);$('bossTxt').textContent=S.rift.guardianKilled?(S.rift.lootSaving?'装备入库中':'点击左侧退出'):S.rift.guardianSpawned?'击败秘境守卫':`${progress}/${S.rift.progressNeed}`;$('bossFill').style.width=`${S.rift.guardianSpawned?100:clamp(progress/S.rift.progressNeed*100,0,100)}%`};
window.updateFeedback=function(dt){baseFeedback(dt);if(!isRift()){updateRiftExitBtn();return}flushRiftRecycle();if(!S.over&&!S.rift.guardianKilled&&S.time>=S.rift.timeLimit)end(false);updateRiftExitBtn()};
window.drawFx=function(){baseDrawFx()};
window.enemyAttr=function(e,total){if(!isRift())return baseAttr(e,total);if(!e.boss&&!e.elite)return null;let l=S.rift.layer,type=e.boss?'shadow':e.type==='wraith'?'frost':e.type==='healer'?'holy':e.type==='charger'||e.type==='lavaImp'?'fire':e.type==='eye'||e.type==='voidWalker'?'arcane':e.type==='sporeSlime'?'poison':e.type==='bloodAcolyte'?'shadow':'physical',amount=total*Math.min(.75,.08+l*.012);return{type,amount,source:{boss:e.boss,elite:e.elite},color:{frost:'#7dd3fc',physical:'#cbd5e1',holy:'#fde68a',arcane:'#c084fc',fire:'#fb923c',shadow:'#a78bfa',poison:'#86efac'}[type]}};
window.dropEquipmentFromBoss=function(x,y){let old=S.endlessLayer;if(isRift())S.endlessLayer=S.rift.layer;try{return baseDrop(x,y)}finally{S.endlessLayer=old}};
window.deaths=function(){if(!isRift())return baseDeaths();for(const e of S.enemies)if(e.hp<=0&&!e.dead){e.dead=true;grantRiftKill(e);let coin=goldDrop(e);if(coin)S.gold+=coin;if(e.boss){S.bossKills++;S.rift.guardianKilled=true;S.rift.finished=false;S.cleared=true;S.clearTime=S.time;dropEquipmentFromBoss(e.x,e.y);S.enemies.forEach(m=>{if(!m.boss)m.dead=true});showNotice('秘境守卫已击败，装备入库后点击左侧退出秘境');updateRiftExitBtn()}if(e.split&&!e.mini)for(let j=0;j<e.split&&S.enemies.length<(S.rift.poolCap||riftActiveCap(S.rift.layer));j++){let a=rand(0,TAU),hp=e.max*.32;riftEnemy({x:e.x+Math.cos(a)*18,y:e.y+Math.sin(a)*18,type:'slime',img:'slime',r:16,hp,max:hp,spd:e.spd*1.35,xp:3,boss:false,hit:0,slow:0,phase:rand(0,TAU),shoot:2,anim:rand(0,4),mini:true,dmgMul:e.dmgMul||1})}for(let i=0;i<(e.boss?18:5);i++)S.parts.push({x:e.x,y:e.y,vx:rand(-80,80),vy:rand(-80,80),life:rand(.25,.7),max:.7,a:1,c:e.boss?'#111':e.elite?'#a855f7':'#f43f5e'});recycleRiftEnemy(e)}S.enemies=S.enemies.filter(e=>!e.dead)};
window.saveData=function(){let d=baseSave();if(d&&isRift()){let r={...S.rift};delete r.enemyPool;delete r.recycleQueue;d.rift=r}return d};
window.loadGame=async function(){await baseLoad();try{let d=await kvGet(runSaveKey());if(S&&d?.rift){S.rift=d.rift;S.rift.breaks={life:S.rift.breaks?.life||0};S.rift.milestones=S.rift.milestones||{};S.rift.mapTheme=riftMap(S.rift.mapTheme).id;S.rift.mapName=riftMapName();S.rift.progressNeed=NEED;S.rift.poolCap=riftActiveCap(S.rift.layer);S.rift.bossAddCap=riftBossAddCap(S.rift.layer);S.nextBossKills=NEED;if(S.mapId==='rift'&&!S.terrain?.length)S.terrain=terrainSeed();updateHud()}}catch(e){console.warn('秘境进度恢复失败:',e.message)}};
window.end=function(win){if(!isRift()){let grant=!!win&&S?.mapId!=='rift'&&!S?.endless;let out=baseEnd(win);if(grant)init().then(()=>{cache.keys+=8;return storePut(cache)}).then(()=>showNotice('普通模式通关奖励：秘境门票 +8')).catch(e=>console.warn('秘境门票奖励失败:',e.code,e.message));return out}if(S.ending)return;S.ending=true;S.over=true;S.paused=true;S.rift.finished=true;clearRunSave?.().catch(e=>console.warn('清理秘境战斗存档失败:',e.code,e.message));let layer=S.rift.layer,progress=Math.min(S.kills,NEED),time=S.time,clearWin=!!win;Rift.finishRun({win:clearWin,layer,time,classId:S.player.cls}).then(r=>{let el=$('riftReward');if(el)el.textContent=clearWin?`秘境尘 +${r.gainDust}，解锁至 ${r.maxLayer} 层，当前门票 ${r.keys}${r.ticketDrop?'，Boss 掉落门票 +1':''}`:`秘境失败，保留进度奖励：秘境尘 +${r.gainDust}，当前门票 ${r.keys}`}).catch(e=>{let el=$('riftReward');if(el)el.textContent='秘境奖励保存失败，请稍后重试。';console.error('秘境奖励保存失败:',e.code,e.message,e.stack)});let run={gold:S.gold,time,bossKills:S.bossKills||0,endlessLayer:layer,endlessTime:time,level:S.player.lv,goals:0,classId:S.player.cls,win:clearWin};$('endTitle').textContent=clearWin?'秘境通关！':'秘境失败';$('endText').innerHTML=`<p>${clearWin?`你在 ${fmt(time)} 内击败秘境守卫，完成第 ${layer} 层。`:`第 ${layer} 层挑战超时或阵亡，进度 ${progress}/${NEED}。`}</p><p>消灭 ${S.kills} 点进度，等级 ${S.player.lv}，金币 ${S.gold}。</p><p>最强技能：${esc(strongestSkill())}；完成进化：${Object.keys(S.evolutions||{}).length}。</p><p id="riftReward" class="rewardHint">正在结算秘境奖励...</p><p id="soulReward" class="rewardHint">正在结算灵魂金币...</p><p id="seasonReward" class="rewardHint">正在结算赛季经验...</p>`;$('endlessBtn').classList.add('hidden');$('end').classList.remove('hidden');if(S.rewardSettled)return;S.rewardSettled=true;Progression.addRunReward(run).then(r=>{$('soulReward').textContent=`本局获得 ${r.gold} 灵魂金币、${r.core} 魔核。`}).catch(e=>{console.error('灵魂金币结算失败:',e.code,e.message,e.stack)});Season.addRunXp(run).then(r=>{$('seasonReward').textContent=r?`赛季经验 +${r.gain}，赛季等级 ${r.level}/${Season.cap()}`:'赛季尚未开启'}).catch(e=>{console.error('赛季经验结算失败:',e.code,e.message,e.stack)})}
}
